from typing import List, Optional

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def build_list(nums: List[int]) -> Optional[ListNode]:
    dummy = ListNode(0)
    cur = dummy
    for n in nums:
        cur.next = ListNode(n)
        cur = cur.next
    return dummy.next

def list_to_arr(head: Optional[ListNode]) -> List[int]:
    result = []
    while head:
        result.append(head.val)
        head = head.next
    return result

def reorder_list(head: List[int]) -> List[int]:
    node = build_list(head)
    if not node:
        return []

    # Collect all nodes into an array
    nodes = []
    curr = node
    while curr:
        nodes.append(curr)
        curr = curr.next

    # Use two pointers to reorder in-place
    left, right = 0, len(nodes) - 1
    while left < right:
        nodes[left].next = nodes[right]
        left += 1
        if left == right:
            break
        nodes[right].next = nodes[left]
        right -= 1
    nodes[left].next = None

    return list_to_arr(node)

class ListNode {
  constructor(val = 0, next = null) { this.val = val; this.next = next; }
}
function buildList(nums) {
  const dummy = new ListNode(0); let cur = dummy;
  for (const n of nums) { cur.next = new ListNode(n); cur = cur.next; }
  return dummy.next;
}
function listToArr(head) {
  const res = []; while (head) { res.push(head.val); head = head.next; } return res;
}
function reorderList(head) {
    let node = buildList(head);
    if (!node || !node.next) return listToArr(node);
    // Find middle
    let slow = node, fast = node;
    while (fast.next && fast.next.next) { slow = slow.next; fast = fast.next.next; }
    // Reverse second half
    let second = slow.next;
    slow.next = null;
    let prev = null;
    while (second) { const tmp = second.next; second.next = prev; prev = second; second = tmp; }
    second = prev;
    // Merge
    let first = node;
    while (second) {
        const tmp1 = first.next, tmp2 = second.next;
        first.next = second; second.next = tmp1;
        first = tmp1; second = tmp2;
    }
    return listToArr(node);
}
